{
  "name": "MetalForge Art & Sound Studio",
  "description": "An interactive digital art studio with AI-powered effects, integrated marketplace, and a heavy metal music generator for thrash and death metal soundscapes.",
  "requestFramePermissions": [
    "camera",
    "microphone"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Artwork {
  id: string;
  title: string;
  image: string;
  price: string;
  creator: string;
  genre: string;
}

export interface MetalRiff {
  id: string;
  title: string;
  bpm: number;
  description: string;
  style: 'thrash' | 'death' | 'black';
  audioUrl?: string;
}

export enum StudioMode {
  PAINT = 'PAINT',
  MUSIC = 'MUSIC',
  MARKET = 'MARKET'
}

import { GoogleGenAI, Type } from "@google/genai";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const applyAIEffect = async (base64Image: string, prompt: string) => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        {
          inlineData: {
            data: base64Image.split(',')[1],
            mimeType: 'image/png',
          },
        },
        { text: `Apply this artistic effect to the image: ${prompt}. Maintain the heavy metal/dark aesthetic.` },
      ],
    },
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  return null;
};

export const generateMetalDescription = async (artDescription: string) => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Based on this artwork description: "${artDescription}", generate a short, intense death metal or thrash metal song title and a brief description of the guitar riffs and drum patterns.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          description: { type: Type.STRING },
          bpm: { type: Type.NUMBER }
        }
      }
    }
  });
  return JSON.parse(response.text);
};

export const generateDeathMetalVocal = async (text: string) => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: `In a gutteral, deep, demonic death metal voice, growl: ${text}` }] }],
    config: {
      responseModalities: ['AUDIO'],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: 'Fenrir' }, // Fenrir sounds heavy
        },
      },
    },
  });
  return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
};

import React, { useRef, useEffect, useState } from 'react';
import { Palette, Eraser, Sparkles, Save, Trash2, Download } from 'lucide-react';
import { applyAIEffect } from '../services/geminiService';

interface CanvasProps {
  onSave: (imageUrl: string) => void;
}

const Canvas: React.FC<CanvasProps> = ({ onSave }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isDrawing, setIsDrawing] = useState(false);
  const [color, setColor] = useState('#ff0000');
  const [brushSize, setBrushSize] = useState(5);
  const [isEraser, setIsEraser] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [aiPrompt, setAiPrompt] = useState('Add demonic wings and a metallic texture');

  useEffect(() => {
    const canvas = canvasRef.current;
    if (canvas) {
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.fillStyle = '#1e293b';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
      }
    }
  }, []);

  const startDrawing = (e: React.MouseEvent | React.TouchEvent) => {
    setIsDrawing(true);
    draw(e);
  };

  const stopDrawing = () => {
    setIsDrawing(false);
    const canvas = canvasRef.current;
    if (canvas) {
      const ctx = canvas.getContext('2d');
      ctx?.beginPath();
    }
  };

  const draw = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawing) return;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const rect = canvas.getBoundingClientRect();
    const x = ('touches' in e) ? e.touches[0].clientX - rect.left : (e as React.MouseEvent).clientX - rect.left;
    const y = ('touches' in e) ? e.touches[0].clientY - rect.top : (e as React.MouseEvent).clientY - rect.top;

    ctx.lineWidth = brushSize;
    ctx.lineCap = 'round';
    ctx.strokeStyle = isEraser ? '#1e293b' : color;

    ctx.lineTo(x, y);
    ctx.stroke();
    ctx.beginPath();
    ctx.moveTo(x, y);
  };

  const clearCanvas = () => {
    const canvas = canvasRef.current;
    if (canvas) {
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.fillStyle = '#1e293b';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
      }
    }
  };

  const handleAIAction = async () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    setIsProcessing(true);
    try {
      const base64 = canvas.toDataURL('image/png');
      const result = await applyAIEffect(base64, aiPrompt);
      if (result) {
        const img = new Image();
        img.onload = () => {
          const ctx = canvas.getContext('2d');
          ctx?.drawImage(img, 0, 0);
        };
        img.src = result;
      }
    } catch (error) {
      console.error("AI Effect Failed", error);
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="flex flex-col gap-4 w-full max-w-5xl mx-auto p-4 bg-slate-900 border border-slate-700 rounded-xl shadow-2xl">
      <div className="flex flex-wrap items-center justify-between gap-4 p-4 bg-slate-800 rounded-lg">
        <div className="flex items-center gap-4">
          <input
            type="color"
            value={color}
            onChange={(e) => {
              setColor(e.target.value);
              setIsEraser(false);
            }}
            className="w-10 h-10 bg-transparent border-none cursor-pointer"
          />
          <div className="flex gap-2">
            {[1, 5, 10, 20].map((size) => (
              <button
                key={size}
                onClick={() => setBrushSize(size)}
                className={`w-8 h-8 rounded-full border border-slate-600 flex items-center justify-center transition ${brushSize === size ? 'bg-red-600' : 'bg-slate-700 hover:bg-slate-600'}`}
              >
                <div className="bg-white rounded-full" style={{ width: size, height: size }}></div>
              </button>
            ))}
          </div>
          <button
            onClick={() => setIsEraser(!isEraser)}
            className={`p-2 rounded-lg transition ${isEraser ? 'bg-red-600' : 'bg-slate-700 hover:bg-slate-600'}`}
          >
            <Eraser size={20} />
          </button>
          <button
            onClick={clearCanvas}
            className="p-2 rounded-lg bg-slate-700 hover:bg-red-900 transition text-red-400"
          >
            <Trash2 size={20} />
          </button>
        </div>

        <div className="flex items-center gap-2">
          <input 
            type="text" 
            value={aiPrompt}
            onChange={(e) => setAiPrompt(e.target.value)}
            placeholder="AI Effect Prompt..."
            className="px-4 py-2 bg-slate-700 rounded-lg border border-slate-600 focus:outline-none focus:border-red-500 w-48 md:w-64"
          />
          <button
            onClick={handleAIAction}
            disabled={isProcessing}
            className="flex items-center gap-2 px-4 py-2 bg-purple-700 hover:bg-purple-600 rounded-lg transition disabled:opacity-50"
          >
            <Sparkles size={20} />
            {isProcessing ? 'Forging...' : 'AI Mutation'}
          </button>
          <button
            onClick={() => onSave(canvasRef.current?.toDataURL('image/png') || '')}
            className="flex items-center gap-2 px-4 py-2 bg-red-700 hover:bg-red-600 rounded-lg transition"
          >
            <Save size={20} />
            Publish Art
          </button>
        </div>
      </div>

      <canvas
        ref={canvasRef}
        width={1000}
        height={600}
        onMouseDown={startDrawing}
        onMouseUp={stopDrawing}
        onMouseOut={stopDrawing}
        onMouseMove={draw}
        onTouchStart={startDrawing}
        onTouchEnd={stopDrawing}
        onTouchMove={draw}
        className="w-full h-auto cursor-crosshair bg-slate-800 rounded-lg border-2 border-slate-700"
      />

      <div className="flex justify-between items-center text-xs text-slate-400 italic px-2">
        <span>* Canvas set to High Resolution (1000x600)</span>
        <span>Drag to paint your metal vision</span>
      </div>
    </div>
  );
};

export default Canvas;

import React, { useState } from 'react';
import { Music, Play, Volume2, AudioLines, Flame, Ghost } from 'lucide-react';
import { generateMetalDescription, generateDeathMetalVocal } from '../services/geminiService';
import { LineChart, Line, ResponsiveContainer } from 'recharts';

const MusicStudio: React.FC = () => {
  const [mood, setMood] = useState('Brutal Death Metal');
  const [lyrics, setLyrics] = useState('The abyss consumes all hope');
  const [riffInfo, setRiffInfo] = useState<any>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [audioBase64, setAudioBase64] = useState<string | null>(null);

  const handleGenerate = async () => {
    setIsGenerating(true);
    try {
      const info = await generateMetalDescription(mood);
      setRiffInfo(info);

      const audioData = await generateDeathMetalVocal(lyrics);
      if (audioData) {
        setAudioBase64(audioData);
      }
    } catch (error) {
      console.error(error);
    } finally {
      setIsGenerating(false);
    }
  };

  const playAudio = () => {
    if (!audioBase64) return;
    const binary = atob(audioBase64);
    const bytes = new Uint8Array(binary.length);
    for (let i = 0; i < binary.length; i++) {
      bytes[i] = binary.charCodeAt(i);
    }
    const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

    // Process raw PCM
    const dataInt16 = new Int16Array(bytes.buffer);
    const frameCount = dataInt16.length;
    const buffer = audioContext.createBuffer(1, frameCount, 24000);
    const channelData = buffer.getChannelData(0);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i] / 32768.0;
    }

    const source = audioContext.createBufferSource();
    source.buffer = buffer;
    source.connect(audioContext.destination);
    source.start();
  };

  // Dummy visualizer data
  const data = Array.from({ length: 40 }, () => ({ val: Math.random() * 100 }));

  return (
    <div className="flex flex-col gap-6 w-full max-w-4xl mx-auto p-8 bg-slate-900 border-2 border-red-900 rounded-2xl shadow-[0_0_50px_rgba(153,27,27,0.2)]">
      <div className="flex items-center gap-4 border-b border-red-900 pb-4">
        <AudioLines className="text-red-600" size={32} />
        <h2 className="text-3xl font-metal text-red-600 uppercase tracking-widest">Riff Forge</h2>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="space-y-4">
          <label className="block text-sm font-bold text-slate-400 uppercase">Atmosphere</label>
          <select 
            value={mood}
            onChange={(e) => setMood(e.target.value)}
            className="w-full px-4 py-3 bg-slate-800 border border-slate-700 rounded-lg text-white focus:ring-2 focus:ring-red-600 outline-none"
          >
            <option>Old School Thrash</option>
            <option>Gutteral Death Metal</option>
            <option>Blackened Speed Metal</option>
            <option>Industrial Doom</option>
          </select>

          <label className="block text-sm font-bold text-slate-400 uppercase">Growl Lyrics / Text</label>
          <textarea 
            value={lyrics}
            onChange={(e) => setLyrics(e.target.value)}
            placeholder="Type lyrics for the death metal growl..."
            className="w-full h-32 px-4 py-3 bg-slate-800 border border-slate-700 rounded-lg text-white focus:ring-2 focus:ring-red-600 outline-none resize-none"
          />

          <button
            onClick={handleGenerate}
            disabled={isGenerating}
            className="w-full py-4 bg-red-800 hover:bg-red-700 text-white font-bold rounded-lg transition flex items-center justify-center gap-3 shadow-lg shadow-red-900/20"
          >
            {isGenerating ? <Ghost className="animate-pulse" /> : <Flame />}
            {isGenerating ? 'SUMMONING SOUND...' : 'FORGE SOUNDSCAPE'}
          </button>
        </div>

        <div className="bg-black/50 p-6 rounded-xl border border-red-900/30 flex flex-col justify-between">
          <div>
            <h3 className="text-xl font-metal text-red-500 mb-2">{riffInfo?.title || 'No Project Loaded'}</h3>
            <p className="text-slate-400 text-sm italic leading-relaxed">
              {riffInfo?.description || 'Configure your atmosphere and forge a new metallic soundscape.'}
            </p>
            {riffInfo && (
              <div className="mt-4 flex items-center gap-2">
                <span className="bg-red-900/40 text-red-300 text-xs px-2 py-1 rounded">BPM: {riffInfo.bpm}</span>
                <span className="bg-slate-800 text-slate-400 text-xs px-2 py-1 rounded">Intensity: 100%</span>
              </div>
            )}
          </div>

          <div className="mt-8 h-24 w-full opacity-50">
             <ResponsiveContainer width="100%" height="100%">
               <LineChart data={data}>
                 <Line type="step" dataKey="val" stroke="#dc2626" strokeWidth={2} dot={false} />
               </LineChart>
             </ResponsiveContainer>
          </div>

          <button
            disabled={!audioBase64}
            onClick={playAudio}
            className={`mt-4 w-full py-3 flex items-center justify-center gap-2 rounded-lg font-bold transition ${audioBase64 ? 'bg-green-800 hover:bg-green-700 text-white' : 'bg-slate-800 text-slate-600 cursor-not-allowed'}`}
          >
            <Play fill="currentColor" size={20} />
            PLAY GROWL
          </button>
        </div>
      </div>
    </div>
  );
};

export default MusicStudio;

