export class MetalSynth {
  private ctx: AudioContext | null = null;
  private isPlaying: boolean = false;
  private nextNoteTime: number = 0;
  private bpm: number = 140;
  private timerId: number | null = null;

  constructor() {
    this.ctx = null;
  }

  private initCtx() {
    if (!this.ctx) {
      this.ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
  }

  private createDistortionCurve(amount: number = 50) {
    const k = amount;
    const n_samples = 44100;
    const curve = new Float32Array(n_samples);
    const deg = Math.PI / 180;
    for (let i = 0; i < n_samples; ++i) {
      const x = (i * 2) / n_samples - 1;
      curve[i] = ((3 + k) * x * 20 * deg) / (Math.PI + k * Math.abs(x));
    }
    return curve;
  }

  private playChug(time: number) {
    if (!this.ctx) return;

    // Oscillator for the "chug"
    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();
    const distortion = this.ctx.createWaveShaper();
    const filter = this.ctx.createBiquadFilter();

    distortion.curve = this.createDistortionCurve(400);
    distortion.oversample = '4x';

    filter.type = 'lowpass';
    filter.frequency.setValueAtTime(400, time);
    filter.frequency.exponentialRampToValueAtTime(100, time + 0.1);

    osc.type = 'sawtooth';
    osc.frequency.setValueAtTime(40 + Math.random() * 10, time); // Low E chug

    gain.gain.setValueAtTime(0.3, time);
    gain.gain.exponentialRampToValueAtTime(0.001, time + 0.15);

    osc.connect(distortion);
    distortion.connect(filter);
    filter.connect(gain);
    gain.connect(this.ctx.destination);

    osc.start(time);
    osc.stop(time + 0.2);
  }

  private playKick(time: number) {
    if (!this.ctx) return;
    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();

    osc.frequency.setValueAtTime(150, time);
    osc.frequency.exponentialRampToValueAtTime(0.01, time + 0.1);

    gain.gain.setValueAtTime(1, time);
    gain.gain.exponentialRampToValueAtTime(0.01, time + 0.1);

    osc.connect(gain);
    gain.connect(this.ctx.destination);

    osc.start(time);
    osc.stop(time + 0.1);
  }

  private scheduler() {
    if (!this.ctx) return;
    while (this.nextNoteTime < this.ctx.currentTime + 0.1) {
      this.playChug(this.nextNoteTime);
      if (Math.random() > 0.5) {
        this.playKick(this.nextNoteTime);
      }
      this.nextNoteTime += 60.0 / (this.bpm * 2); // 8th notes
    }
    this.timerId = window.setTimeout(() => this.scheduler(), 25);
  }

  public start(bpm: number = 140) {
    this.initCtx();
    if (this.ctx?.state === 'suspended') {
      this.ctx.resume();
    }
    this.bpm = bpm;
    this.nextNoteTime = this.ctx!.currentTime;
    this.isPlaying = true;
    this.scheduler();
  }

  public stop() {
    this.isPlaying = false;
    if (this.timerId) {
      clearTimeout(this.timerId);
    }
  }

  public setBpm(bpm: number) {
    this.bpm = bpm;
  }
}

export const metalSynth = new MetalSynth();

import React, { useState, useEffect, useRef } from 'react';
import { Play, Square, AudioLines, Flame, Ghost, Volume2, Activity } from 'lucide-react';
import { generateMetalDescription, generateDeathMetalVocal } from '../services/geminiService';
import { metalSynth } from '../services/metalSynth';
import { LineChart, Line, ResponsiveContainer } from 'recharts';

const MusicStudio: React.FC = () => {
  const [mood, setMood] = useState('Brutal Death Metal');
  const [lyrics, setLyrics] = useState('The abyss consumes all hope');
  const [riffInfo, setRiffInfo] = useState<any>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [audioBase64, setAudioBase64] = useState<string | null>(null);
  const [isBackingPlaying, setIsBackingPlaying] = useState(false);
  const [visualizerData, setVisualizerData] = useState(Array.from({ length: 40 }, () => ({ val: 10 })));

  const timerRef = useRef<number | null>(null);

  useEffect(() => {
    if (isBackingPlaying || isGenerating) {
      timerRef.current = window.setInterval(() => {
        setVisualizerData(prev => prev.map(() => ({ val: Math.random() * (isBackingPlaying ? 80 : 20) + 10 })));
      }, 100);
    } else {
      if (timerRef.current) clearInterval(timerRef.current);
      setVisualizerData(Array.from({ length: 40 }, () => ({ val: 5 })));
    }
    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [isBackingPlaying, isGenerating]);

  const handleGenerate = async () => {
    setIsGenerating(true);
    try {
      const info = await generateMetalDescription(mood);
      setRiffInfo(info);
      if (isBackingPlaying) {
        metalSynth.setBpm(info.bpm || 140);
      }

      const audioData = await generateDeathMetalVocal(lyrics);
      if (audioData) {
        setAudioBase64(audioData);
      }
    } catch (error) {
      console.error(error);
    } finally {
      setIsGenerating(false);
    }
  };

  const toggleBackingTrack = () => {
    if (isBackingPlaying) {
      metalSynth.stop();
    } else {
      metalSynth.start(riffInfo?.bpm || 140);
    }
    setIsBackingPlaying(!isBackingPlaying);
  };

  const playAudio = () => {
    if (!audioBase64) return;
    const binary = atob(audioBase64);
    const bytes = new Uint8Array(binary.length);
    for (let i = 0; i < binary.length; i++) {
      bytes[i] = binary.charCodeAt(i);
    }
    const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

    const dataInt16 = new Int16Array(bytes.buffer);
    const frameCount = dataInt16.length;
    const buffer = audioContext.createBuffer(1, frameCount, 24000);
    const channelData = buffer.getChannelData(0);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i] / 32768.0;
    }

    const source = audioContext.createBufferSource();
    source.buffer = buffer;
    source.connect(audioContext.destination);
    source.start();
  };

