          val: Math.random() * (isPlaying ? 80 : 20) + (isPlaying ? 15 : 5) 
        })));
      }, 70);
    } else {
      if (visualRef.current) clearInterval(visualRef.current);
      setVizData(Array.from({ length: 60 }, () => ({ val: 2 })));
    }
    return () => { if (visualRef.current) clearInterval(visualRef.current); };
  }, [isPlaying, isForging]);

  const forgeBrutality = async () => {
    setIsForging(true);
    setVocalAudio(null);
    try {
      // 1. Tech Specs
      const structure = await generateMusicalStructure(prompt);
      setTrackData(structure);

      if (isPlaying) {
        metalSynth.updateParams(structure.bpm, structure.intensity);
      }

      // 2. Vocals
      const audio = await generateMusicalVocal(structure.lyrics, prompt);
      if (audio) setVocalAudio(audio);

    } catch (e) {
      console.error("The forge failed to ignite.", e);
    } finally {
      setIsForging(false);
