      <div className="flex flex-wrap items-center justify-between gap-6 bg-slate-900 border-2 border-red-950 p-6 rounded-3xl shadow-2xl">
        <div className="flex items-center gap-5">
          <div className="p-4 bg-red-900/20 border border-red-900/40 rounded-2xl">
            <Music4 className="text-red-600" size={36} />
          </div>
          <div>
            <h2 className="text-3xl font-metal text-white tracking-widest uppercase">Sonic Overlord</h2>
            <div className="flex items-center gap-2">
              <div className={`w-2 h-2 rounded-full ${isPlaying ? 'bg-red-500 animate-ping' : 'bg-slate-700'}`}></div>
              <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Neural Link: {isPlaying ? 'Synchronized' : 'Ready'}</span>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-6 bg-black/40 p-4 rounded-2xl border border-slate-800">
          <div className="space-y-2">
            <span className="text-[9px] font-bold text-slate-500 uppercase">Mix: Guitars</span>
            <input 
              type="range" min="0" max="1" step="0.1" 
              value={guitarVol}
              onChange={(e) => {
                const v = parseFloat(e.target.value);
                setGuitarVol(v);
                metalSynth.guitarVolume = v;
              }}
              className="w-24 h-1 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-red-600"
            />
          </div>
          <div className="space-y-2">
            <span className="text-[9px] font-bold text-slate-500 uppercase">Mix: Percussion</span>
            <input 
              type="range" min="0" max="1" step="0.1" 
              value={drumVol}
              onChange={(e) => {
                const v = parseFloat(e.target.value);
                setDrumVol(v);
                metalSynth.drumVolume = v;
              }}
              className="w-24 h-1 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-red-600"
            />
          </div>
        </div>

        <button 
          onClick={toggleEngine}
          disabled={!trackData && !isPlaying}
          className={`px-10 py-4 rounded-2xl font-bold flex items-center gap-3 transition-all transform hover:scale-105 active:scale-95 shadow-2xl disabled:opacity-30 disabled:cursor-not-allowed ${isPlaying ? 'bg-red-600 text-white' : 'bg-slate-800 text-slate-400 border border-slate-700 hover:text-white'}`}
        >
          {isPlaying ? <Square size={20} fill="white" /> : <Play size={20} fill="currentColor" />}
          <span className="uppercase tracking-widest">{isPlaying ? 'Halt Engine' : 'Ignite Engine'}</span>
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Input/Prompt Section */}
        <div className="lg:col-span-4 flex flex-col gap-6">
          <div className="bg-slate-900/50 p-8 rounded-3xl border border-slate-800 flex flex-col h-full">
            <div className="mb-6 flex items-center gap-3">
