            >
              <div className="absolute inset-0 bg-white/10 translate-x-[-100%] group-hover:translate-x-[100%] transition-transform duration-500 skew-x-[-20deg]"></div>
              {isForging ? <Ghost className="animate-spin" /> : <Flame />}
              <span className="uppercase tracking-[0.2em]">{isForging ? 'Forging...' : 'Forge Tracks'}</span>
            </button>
          </div>
        </div>

        {/* Display/Console Section */}
        <div className="lg:col-span-8 space-y-6">
          <div className="bg-black p-10 rounded-3xl border border-red-900/10 flex flex-col min-h-[500px] shadow-[inset_0_0_100px_rgba(153,27,27,0.05)]">
            <div className="flex-1">
              <div className="flex justify-between items-start mb-8">
                <div>
                  <h3 className="text-4xl font-metal text-white mb-2 uppercase tracking-tighter">
                    {trackData?.title || 'System Idle'}
                  </h3>
                  <div className="flex gap-3">
                    <span className="text-[10px] font-bold text-red-600/60 uppercase">{trackData?.genreMatch || 'Unknown Genre'}</span>
                    <span className="text-[10px] font-bold text-slate-700 uppercase">ID: {Math.random().toString(16).slice(2,8).toUpperCase()}</span>
                  </div>
                </div>
                {trackData && (
                  <div className="text-right space-y-1">
                    <div className="text-2xl font-mono text-red-600 font-bold">{trackData.bpm} BPM</div>
                    <div className="text-[9px] text-slate-500 uppercase font-bold">Intensity: {trackData.intensity}/10</div>
                  </div>
                )}
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-10 mb-10">
                <div className="space-y-4">
                  <h4 className="text-[10px] font-bold text-slate-600 uppercase tracking-widest flex items-center gap-2">
