  const [forgeProgress, setForgeProgress] = useState<string | null>(null);
  const [viz, setViz] = useState(Array.from({ length: 40 }, () => ({ val: 5 })));

  const vizTimer = useRef<number | null>(null);

  useEffect(() => {
    if (isPlaying || isForging) {
      vizTimer.current = window.setInterval(() => {
        setViz(prev => prev.map(() => ({ 
          val: Math.random() * (isPlaying ? 80 : 20) + (isPlaying ? 15 : 5) 
        })));
