    } else {
      if (vizTimer.current) clearInterval(vizTimer.current);
      setViz(Array.from({ length: 40 }, () => ({ val: 2 })));
    }
    return () => { if (vizTimer.current) clearInterval(vizTimer.current); };
  }, [isPlaying, isForging]);

  const generateSong = async () => {
    setIsForging(true);
    setTrack(null);
    setVocalData(null);
