import { generateMusicalStructure, generateMusicalVocal } from '../services/geminiService';
import { metalSynth } from '../services/metalSynth';
import { LineChart, Line, ResponsiveContainer } from 'recharts';

const MusicStudio: React.FC = () => {
  const [style, setStyle] = useState('Heavy Thrash Metal, 180bpm, aggressive drums');
  const [lyrics, setLyrics] = useState('Into the fire, the soul remains, breaking the walls, shedding the chains.');
  const [isGenerating, setIsGenerating] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [track, setTrack] = useState<any>(null);
  const [vocalAudio, setVocalAudio] = useState<string | null>(null);
  const [vizData, setVizData] = useState(Array.from({ length: 40 }, () => ({ val: 5 })));

  const timer = useRef<number | null>(null);

  useEffect(() => {
    if (isPlaying || isGenerating) {
      timer.current = window.setInterval(() => {
        setVizData(prev => prev.map(() => ({ 
          val: Math.random() * (isPlaying ? 80 : 15) + (isPlaying ? 10 : 5) 
        })));
      }, 70);
    } else {
      if (timer.current) clearInterval(timer.current);
      setVizData(Array.from({ length: 40 }, () => ({ val: 2 })));
    }
    return () => { if (timer.current) clearInterval(timer.current); };
  }, [isPlaying, isGenerating]);

  const handleGenerate = async () => {
    setIsGenerating(true);
    setTrack(null);
    setVocalAudio(null);
    try {
      // Step 1: Generate technical track structure from prompts
      const composition = await generateMusicalStructure(lyrics, style);
      metalSynth.setPatterns({
        kick: composition.kick,
        snare: composition.snare,
        riff: composition.riff,
        freqs: composition.freqs
      });
      setTrack(composition);

      // Step 2: Generate vocal audio
      const audio = await generateMusicalVocal(composition.lyrics, style);
      if (audio) setVocalAudio(audio);

    } catch (error) {
      console.error("Generation failed", error);
    } finally {
      setIsGenerating(false);
    }
  };

  const togglePlayback = () => {
    if (isPlaying) {
      metalSynth.stop();
    } else if (track) {
      metalSynth.start(track.bpm, track.intensity);
      if (vocalAudio) playVocalBuffer();
    }
    setIsPlaying(!isPlaying);
  };

  const playVocalBuffer = () => {
    if (!vocalAudio) return;
    const binary = atob(vocalAudio);
    const bytes = new Uint8Array(binary.length);
    for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
    const ctx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    const dataInt16 = new Int16Array(bytes.buffer);
    const buffer = ctx.createBuffer(1, dataInt16.length, 24000);
    const ch = buffer.getChannelData(0);
    for (let i = 0; i < dataInt16.length; i++) ch[i] = dataInt16[i] / 32768.0;
    const src = ctx.createBufferSource();
    src.buffer = buffer;
    src.connect(ctx.destination);
    src.start();
  };

  return (
    <div className="w-full max-w-4xl mx-auto p-4 space-y-8">
      {/* Input Section */}
      <div className="bg-slate-900 border border-slate-800 p-8 rounded-[2rem] shadow-2xl space-y-6">
