            />
          </div>
        </div>

        <button 
          onClick={handleGenerate}
          disabled={isGenerating}
          className="w-full py-5 bg-red-600 hover:bg-red-500 text-white font-bold rounded-2xl transition-all shadow-xl flex items-center justify-center gap-3 disabled:opacity-50"
        >
          {isGenerating ? <Ghost className="animate-spin" /> : <Sparkles />}
          <span className="uppercase tracking-[0.2em]">{isGenerating ? 'Synthesizing...' : 'Generate Song'}</span>
        </button>
      </div>

      {/* Result Section */}
      {track && (
        <div className="bg-black/60 border border-red-900/20 p-8 rounded-[2rem] space-y-6 animate-in fade-in slide-in-from-bottom-4">
          <div className="flex flex-wrap items-center justify-between gap-4">
            <div>
              <h2 className="text-4xl font-metal text-white uppercase">{track.title}</h2>
              <p className="text-[10px] text-red-600 font-bold uppercase tracking-widest">{track.bpm} BPM • {style}</p>
