import { GoogleGenAI, Type } from "@google/genai";

// Initialize GoogleGenAI with the API key from environment variables.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateMusicalStructure = async (lyricsPrompt: string, stylePrompt: string) => {
  // Use the ai instance to generate content with gemini-3-flash-preview for musical structure.
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `You are an elite extreme metal producer and composer. 
    Analyze the following style and lyrics prompts to create a unique 16-step technical structure.

    STYLE INFLUENCE: "${stylePrompt}"
    LYRICS THEME: "${lyricsPrompt}"

    Your task:
    1. Determine a precise Metal subgenre (e.g., Technical Death, Blackened Thrash, Sludge, Industrial).
    2. Design a 16-step rhythm pattern for kick, snare, and rhythm guitar (riff).
    3. Generate matching low-end frequencies for the guitar notes (range 40-100Hz).
    4. Craft a brutal 4-line verse that fits the theme.

    Required Output (JSON):
    - title: A powerful, thematic track name.
    - bpm: Tempo between 60 and 280 BPM.
    - intensity: Energy level from 1 (Atmospheric) to 10 (Chaos).
    - kick: Array of 16 numbers (0 or 1) representing the drum machine pattern.
    - snare: Array of 16 numbers (0 or 1) representing the drum machine pattern.
    - riff: Array of 16 numbers (0 or 1) representing the rhythm guitar pattern.
    - freqs: Array of 16 numbers (40-100) representing the note frequency for each step.
    - lyrics: A brutal 4-line verse.
    - description: A short technical note on the compositional approach.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          bpm: { type: Type.NUMBER },
          intensity: { type: Type.NUMBER },
          kick: { type: Type.ARRAY, items: { type: Type.NUMBER } },
          snare: { type: Type.ARRAY, items: { type: Type.NUMBER } },
          riff: { type: Type.ARRAY, items: { type: Type.NUMBER } },
          freqs: { type: Type.ARRAY, items: { type: Type.NUMBER } },
          lyrics: { type: Type.STRING },
          description: { type: Type.STRING }
        },
        required: ["title", "bpm", "intensity", "kick", "snare", "riff", "freqs", "lyrics", "description"]
      }
    }
  });
  // Return the text property directly and parse it as JSON.
  return JSON.parse(response.text.trim());
};

export const generateMusicalVocal = async (lyrics: string, style: string) => {
  // Generate brutal vocals using gemini-2.5-flash-preview-tts with the 'Fenrir' voice.
  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ 
      parts: [{ 
        text: `PERFORM THESE LYRICS AS A BRUTAL METAL VOCALIST. 
        STYLE INFLUENCE: ${style}. 
        Use a deep, rhythmic, guttural growl or high-pitched blackened scream as appropriate for the style. 
        LYRICS: ${lyrics}` 
      }] 
    }],
    config: {
      responseModalities: ['AUDIO'],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: 'Fenrir' },
        },
      },
    },
  });
  // Extract audio data from the candidates array.
  return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
};

export const applyAIEffect = async (base64Image: string, prompt: string) => {
  // Edit the image with AI using gemini-2.5-flash-image based on the prompt.
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        { inlineData: { data: base64Image.split(',')[1], mimeType: 'image/png' } },
        { text: `Apply this artistic effect to the image: ${prompt}. Maintain the heavy metal/dark aesthetic and preserve high-contrast details.` },
      ],
    },
  });

  // Find and return the first part containing image data.
  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
  }
  return null;
};

