                      Rendering preview...
                    </p>
                  ) : htmlPreview ? (
                    <div className="relative border border-slate-700 rounded-lg overflow-hidden bg-slate-950 min-h-[15rem]">
                      <iframe
                        ref={iframeRef}
                        title="UI Preview"
